/*
 * fpclassify() test harness — prints (input_hex, classification) pairs.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static const char *class_name(int cls)
{
    switch (cls) {
    case FP_ZERO: return "ZERO";
    case FP_SUBNORMAL: return "SUBNORMAL";
    case FP_NORMAL: return "NORMAL";
    case FP_INFINITE: return "INFINITE";
    case FP_NAN: return "NAN";
    default: return "UNKNOWN";
    }
}

static void emit(double x)
{
    int cls = fpclassify(x);
    printf("%016llx %s\n", (unsigned long long)d2u(x), class_name(cls));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* 1. Zero values */
static void test_zeros(void)
{
    emit(0.0);
    emit(-0.0);
}

/* 2. Subnormal (denormal) values */
static void test_subnormal(void)
{
    emit_u(0x0000000000000001ULL);  /* smallest positive subnormal */
    emit_u(0x8000000000000001ULL);  /* smallest negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* largest positive subnormal */
    emit_u(0x800fffffffffffffULL);  /* largest negative subnormal */
    emit(DBL_MIN * 0.5);
    emit(-DBL_MIN * 0.5);
}

/* 3. Normal values - small */
static void test_normal_small(void)
{
    emit(DBL_MIN);
    emit(-DBL_MIN);
    emit(1.0e-100);
    emit(-1.0e-100);
    emit(1.0e-50);
    emit(-1.0e-50);
}

/* 4. Normal values - medium */
static void test_normal_medium(void)
{
    emit(0.5);
    emit(-0.5);
    emit(1.0);
    emit(-1.0);
    emit(3.14159);
    emit(-3.14159);
    emit(10.0);
    emit(-10.0);
}

/* 5. Normal values - large */
static void test_normal_large(void)
{
    emit(1.0e100);
    emit(-1.0e100);
    emit(1.0e200);
    emit(-1.0e200);
    emit(DBL_MAX * 0.5);
    emit(-DBL_MAX * 0.5);
}

/* 6. Infinite values */
static void test_infinite(void)
{
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */
    emit(INFINITY);
    emit(-INFINITY);
}

/* 7. NaN values */
static void test_nan(void)
{
    emit_u(0x7ff8000000000000ULL);  /* quiet NaN */
    emit_u(0x7ff0000000000001ULL);  /* signaling NaN */
    emit_u(0xfff8000000000000ULL);  /* negative quiet NaN */
    emit_u(0xfff0000000000001ULL);  /* negative signaling NaN */
    emit(NAN);
}

/* 8. Edge cases and mixed sweep */
static void test_sweep(void)
{
    double vals[] = {
        -DBL_MAX, -1.0e100, -1.0, -DBL_MIN,
        -DBL_MIN * 0.5, 0.0, DBL_MIN * 0.5,
        DBL_MIN, 1.0, 1.0e100, DBL_MAX
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_zeros();
    test_subnormal();
    test_normal_small();
    test_normal_medium();
    test_normal_large();
    test_infinite();
    test_nan();
    test_sweep();
    return 0;
}

