    emit(DBL_MIN, 1.0);
    emit(-DBL_MIN, 1.0);
    emit(1.0e-100, 1.0e-50);
    emit(1.0e-200, 1.0e-100);
}

/* 3. Basic cases */
static void test_basic(void)
{
    emit(5.0, 2.0);
    emit(5.5, 2.5);
    emit(-5.0, 2.0);
    emit(5.0, -2.0);
    emit(-5.0, -2.0);
    emit(7.0, 2.5);
    emit(10.0, 3.0);
}

/* 4. Known quotient cases */
static void test_known(void)
{
    emit(22.0, 7.0);
    emit(100.0, 30.0);
    emit(355.0, 113.0);
    emit(-22.0, 7.0);
    emit(-100.0, 30.0);
    emit(1.5, 0.5);
    emit(3.0, 2.0);
}

/* 5. Large values */
static void test_large(void)
{
    emit(1.0e100, 1.0e50);
    emit(1.0e200, 1.0e100);
    emit(DBL_MAX, 1.0e100);
    emit(-1.0e100, 1.0e50);
    emit(1.0e50, 1.0e100);
}

/* 6. Exact divisibility cases */
static void test_exact(void)
{
    emit(10.0, 5.0);   /* x = 2*y, quo=2 */
    emit(15.0, 5.0);   /* x = 3*y, quo=3 */
    emit(100.0, 10.0); /* x = 10*y, quo=10 */
    emit(-20.0, 4.0);  /* negative exact */
    emit(0.5, 0.5);    /* x = y, quo=1 */
}

/* 7. Sweep through various divisors */
static void test_sweep(void)
{
    double divisors[] = { 0.5, 1.0, 1.5, 2.0, 2.5, 3.0, 3.5, 4.0 };
    int n = sizeof(divisors) / sizeof(divisors[0]);
    for (int i = 0; i < n; i++) {
        emit(10.0, divisors[i]);
        emit(-10.0, divisors[i]);
    }
}

/* 8. Sample across exponent range */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3fc0000000000000ULL, /* 0.125 */
        0x3fd0000000000000ULL, /* 0.25 */
        0x3fe0000000000000ULL, /* 0.5 */
        0x3fe8000000000000ULL, /* 0.75 */
        0x3ff0000000000000ULL, /* 1.0 */
        0x4000000000000000ULL, /* 2.0 */
        0x4008000000000000ULL, /* 3.0 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i], 0x3ff0000000000000ULL);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_basic();
    test_known();
    test_large();
    test_exact();
    test_sweep();
    test_exhaustive_small();
    return 0;
}

