/*
 * ldexp() test harness — prints (mantissa_hex, exponent, output_hex) triples.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static void emit(double x, int exp)
{
    double r = ldexp(x, exp);
    printf("%016llx %d %016llx\n", (unsigned long long)d2u(x), exp, (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits, int exp)
{
    emit(u2d(bits), exp);
}

/* 1. Special values */
static void test_special(void)
{
    emit(0.0, 0);
    emit(-0.0, 0);
    emit(0.0, 10);
    emit_u(0x7ff8000000000000ULL, 0);  /* qNaN */
    emit_u(0x7ff0000000000001ULL, 0);  /* sNaN */
    emit_u(0xfff8000000000000ULL, 0);  /* -NaN */
    emit_u(0x7ff0000000000000ULL, 0);  /* +Inf */
    emit_u(0xfff0000000000000ULL, 0);  /* -Inf */
}

/* 2. Tiny mantissa values */
static void test_tiny_mantissa(void)
{
    emit_u(0x0000000000000001ULL, 0);  /* min denorm */
    emit_u(0x800fffffffffffffULL, 0);  /* mid denorm */
    emit_u(0x000fffffffffffffULL, 0);  /* max denorm */
    emit(DBL_MIN, 0);
    emit(-DBL_MIN, 0);
    emit(1.0e-200, 0);
    emit(-1.0e-200, 0);
}

/* 3. Powers of 2 with various exponents */
static void test_powers_of_2(void)
{
    emit(1.0, 0);
    emit(1.0, 1);
    emit(1.0, 2);
    emit(1.0, 10);
    emit(1.0, -1);
    emit(1.0, -2);
    emit(1.0, -10);
}

/* 4. Fractional and odd mantissas */
static void test_mantissa_values(void)
{
    emit(0.5, 0);
    emit(0.5, 1);
    emit(1.5, 0);
    emit(1.5, 1);
    emit(1.5, 10);
    emit(1.5, -10);
    emit(-1.5, 5);
}

/* 5. Negative exponents (division) */
static void test_negative_exponents(void)
{
    emit(2.0, -1);
    emit(4.0, -2);
    emit(8.0, -3);
    emit(2.0, -100);
    emit(-4.0, -2);
}

/* 6. Large mantissas */
static void test_large_mantissas(void)
{
    emit(1.0e50, 0);
    emit(1.0e100, 0);
    emit(DBL_MAX / (1ULL << 50), 50);
    emit(-DBL_MAX / (1ULL << 50), 50);
}

/* 7. Boundary exponents */
static void test_boundary_exponents(void)
{
    emit(1.0, 1023);   /* near overflow */
    emit(1.0, 1022);
    emit(1.0, -1022);
    emit(1.0, -1023);
    emit(1.0, 1024);   /* overflow */
    emit(1.0, -1074);  /* underflow threshold */
    emit(1.0, -1075);  /* underflow */
}

/* 8. Sweep across exponent range */
static void test_sweep_exponents(void)
{
    int exponents[] = { -100, -50, -10, -5, -1, 0, 1, 5, 10, 50, 100 };
    int n = sizeof(exponents) / sizeof(exponents[0]);
    for (int i = 0; i < n; i++)
        emit(1.5, exponents[i]);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny_mantissa();
    test_powers_of_2();
    test_mantissa_values();
    test_negative_exponents();
    test_large_mantissas();
    test_boundary_exponents();
    test_sweep_exponents();
    return 0;
}

