     1→/*
     2→ * ldexpf() test harness — prints (input_hex, exponent, output_hex) triples.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly ldexpf  (test_ldexpf_opt.elf)
     6→ *   2. Linked with toolchain's default ldexpf        (test_ldexpf_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→static inline uint32_t f2u(float f)
    16→{
    17→    union { float f; uint32_t u; } x;
    18→    x.f = f;
    19→    return x.u;
    20→}
    21→
    22→static inline float u2f(uint32_t u)
    23→{
    24→    union { float f; uint32_t u; } x;
    25→    x.u = u;
    26→    return x.f;
    27→}
    28→
    29→static void emit(float x, int exp)
    30→{
    31→    float r = ldexpf(x, exp);
    32→    printf("%08lx %d %08lx\n",
    33→           (unsigned long)f2u(x), exp, (unsigned long)f2u(r));
    34→}
    35→
    36→static void emit_u(uint32_t bits, int exp)
    37→{
    38→    emit(u2f(bits), exp);
    39→}
    40→
    41→/* ------------------------------------------------------------------ */
    42→/* Test points                                                         */
    43→/* ------------------------------------------------------------------ */
    44→
    45→/* 1. Special values */
    46→static void test_special(void)
    47→{
    48→    int exps[] = { 0, 1, -1, 10, -10 };
    49→    int ne = sizeof(exps) / sizeof(exps[0]);
    50→
    51→    /* Zeros with various exponents */
    52→    for (int j = 0; j < ne; j++) {
    53→        emit(0.0f, exps[j]);
    54→        emit(-0.0f, exps[j]);
    55→    }
    56→
    57→    /* NaN */
    58→    emit_u(0x7fc00000u, 5);   /* qNaN */
    59→    emit_u(0x7f800001u, 5);   /* sNaN */
    60→    emit_u(0xffc00000u, 5);   /* -NaN */
    61→
    62→    /* Infinity */
    63→    emit_u(0x7f800000u, 5);   /* +Inf */
    64→    emit_u(0xff800000u, 5);   /* -Inf */
    65→}
    66→
    67→/* 2. Tiny mantissa values with various exponents */
    68→static void test_tiny(void)
    69→{
    70→    int exps[] = { 0, 1, -1, 10, -10, 100, -100 };
    71→    int ne = sizeof(exps) / sizeof(exps[0]);
    72→
    73→    for (int j = 0; j < ne; j++) {
    74→        emit_u(0x00000001u, exps[j]); /* min denorm */
    75→        emit_u(0x80000001u, exps[j]);
    76→        emit(FLT_MIN, exps[j]);
    77→        emit(-FLT_MIN, exps[j]);
    78→        emit(1.0e-30f, exps[j]);
    79→        emit(-1.0e-30f, exps[j]);
    80→    }
    81→}
    82→
    83→/* 3. Known values: normalize frexp output */
    84→static void test_known(void)
    85→{
    86→    /* frexp returns mantissa in [0.5, 1) with matching exponent */
    87→    float mantissas[] = { 0.5f, 0.75f, 1.0f, -0.5f, -0.75f, -1.0f };
    88→    int exponents[] = { 0, 1, 2, 5, 10, -5, -10 };
    89→
    90→    for (int i = 0; i < 6; i++) {
    91→        for (int j = 0; j < 7; j++) {
    92→            emit(mantissas[i], exponents[j]);
    93→        }
    94→    }
    95→}
    96→
    97→/* 4. Large exponents (overflow/underflow transitions) */
    98→static void test_large_exp(void)
    99→{
   100→    float vals[] = { 0.5f, 1.0f, -1.0f, FLT_MAX };
   101→    int exps[] = { 127, 126, -126, -127, 200, -200 };
   102→
   103→    for (int i = 0; i < 4; i++) {
   104→        for (int j = 0; j < 6; j++) {
   105→            emit(vals[i], exps[j]);
   106→        }
   107→    }
   108→}
   109→
   110→/* 6. Exponent zero (identity) */
   111→static void test_zero_exponent(void)
   112→{
   113→    float vals[] = {
   114→        0.1f, 0.5f, 1.0f, 1.5f, 2.0f, 10.0f, 100.0f,
   115→        -0.1f, -0.5f, -1.0f, -1.5f, -2.0f, -10.0f, -100.0f,
   116→        FLT_MIN, FLT_MAX,
   117→    };
   118→    int n = sizeof(vals) / sizeof(vals[0]);
   119→    for (int i = 0; i < n; i++)
   120→        emit(vals[i], 0);
   121→}
   122→
   123→/* 7. Worst-case exponent combinations */
   124→static void test_hard_exponents(void)
   125→{
   126→    float bases[] = { 0.5f, 1.0f, 1.5f, -1.0f, -2.0f };
   127→    int exps[] = { -50, -25, 0, 25, 50, 100, -100, 126, -126 };
   128→
   129→    for (int i = 0; i < 5; i++) {
   130→        for (int j = 0; j < 9; j++) {
   131→            emit(bases[i], exps[j]);
   132→        }
   133→    }
   134→}
   135→
   136→/* 7b. Sweep exponent range with fixed base */
   137→static void test_sweep_exponent(void)
   138→{
   139→    float base = 1.0f;
   140→    int exps[] = { -100, -50, -10, -5, -1, 0, 1, 5, 10, 50, 100 };
   141→    int ne = sizeof(exps) / sizeof(exps[0]);
   142→
   143→    for (int j = 0; j < ne; j++)
   144→        emit(base, exps[j]);
