    66→    emit(5.5, 2.5);
    67→    emit(-5.0, 2.0);
    68→    emit(5.0, -2.0);
    69→    emit(-5.0, -2.0);
    70→    emit(1.5, 0.5);
    71→    emit(3.0, 2.0);
    72→    emit(10.0, 3.0);
    73→}
    74→
