import re

BASE = "/home/nick/work/picolibc_agentic/libm/machine/riscv/test"

# separator and main marker
SEP = "/* ------------------------------------------------------------------ */"

def edit_file(fname, func_body, last_call):
    path = f"{BASE}/{fname}"
    with open(path) as f:
        content = f.read()

    # Find the LAST occurrence of the separator
    idx = content.rfind(SEP)
    if idx == -1:
        raise ValueError(f"No separator found in {fname}")

    # Insert func_body before that separator
    new_content = content[:idx] + func_body + "\n" + content[idx:]

    # Now insert last_call before "    return 0;\n}"
    new_content = new_content.replace("    return 0;\n}", f"    {last_call};\n    return 0;\n}")

    with open(path, 'w') as f:
        f.write(new_content)
    print(f"  OK: {fname}")

# ── Single-arg double, linear spacing ──────────────────────────────────────────

def make_d1(lo_expr, hi_expr, lo_comment="", hi_comment=""):
    lo_line = f"    double lo = {lo_expr};"
    hi_line = f"    double hi =  {hi_expr};"
    if lo_comment:
        lo_line += f"  /* {lo_comment} */"
    if hi_comment:
        hi_line += f"  /* {hi_comment} */"
    return f"""/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{{
{lo_line}
{hi_line}
    int n = 300;
    for (int i = 0; i < n; i++) {{
        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
        emit(x);
    }}
}}
"""

